import{_ as l,C as o,o as r,c as t,a3 as i,E as n}from"./chunks/framework.CVjg771q.js";const x=JSON.parse('{"title":"六十四卦目录","description":"先建立六十四卦的目录感与分组感，再逐步进入逐卦阅读。","frontmatter":{"title":"六十四卦目录","description":"先建立六十四卦的目录感与分组感，再逐步进入逐卦阅读。"},"headers":[],"relativePath":"yijing/hexagrams/index.md","filePath":"yijing/hexagrams/index.md","lastUpdated":1777633430000}'),s={name:"yijing/hexagrams/index.md"};function c(d,a,h,_,p,u){const e=o("DaoHexagramDirectory");return r(),t("div",null,[a[0]||(a[0]=i('<h1 id="六十四卦目录" tabindex="-1">六十四卦目录 <a class="header-anchor" href="#六十四卦目录" aria-label="Permalink to &quot;六十四卦目录&quot;">​</a></h1><p>这里当前先做“目录层”，不急着一次性生成 64 篇详解。</p><p>更稳的方式仍然是分三步：</p><ol><li>先建立目录页</li><li>再建立统一模板</li><li>学到哪个卦，再补哪个卦</li></ol><h2 id="为什么目录层很重要" tabindex="-1">为什么目录层很重要 <a class="header-anchor" href="#为什么目录层很重要" aria-label="Permalink to &quot;为什么目录层很重要&quot;">​</a></h2><p>很多人读《易》时的困难，不是单卦太难，而是没有整体感。</p><p>目录页的作用就是先让你知道：</p><ul><li>六十四卦不是散乱堆在一起</li><li>它们有次序，也能分组</li><li>你后面逐卦学习时，随时能回到总图里定位</li></ul><h2 id="当前建议结构" tabindex="-1">当前建议结构 <a class="header-anchor" href="#当前建议结构" aria-label="Permalink to &quot;当前建议结构&quot;">​</a></h2><ul><li><code>index.md</code>：六十四卦总入口（本页）</li><li><code>hexagram-01.md</code> ~ <code>hexagram-64.md</code>：64 卦独立页面，每页含完整卦辞、彖传、象传、爻辞（含小象）</li></ul><blockquote><p>解读层（三问、现代重述、我的理解）已预留，随学习进度填入。</p></blockquote><h2 id="后续可记录字段" tabindex="-1">后续可记录字段 <a class="header-anchor" href="#后续可记录字段" aria-label="Permalink to &quot;后续可记录字段&quot;">​</a></h2><ul><li>卦序</li><li>卦名</li><li>上下卦</li><li>卦辞</li><li>核心关键词</li><li>三问解读</li><li>关联专题</li><li>参考来源</li></ul>',13)),n(e),a[1]||(a[1]=i('<h2 id="当前状态" tabindex="-1">当前状态 <a class="header-anchor" href="#当前状态" aria-label="Permalink to &quot;当前状态&quot;">​</a></h2><p>64 卦原典层已完整建档，每卦独立页面包含：卦辞、彖传、象传、爻辞（含小象）。 解读层（三问解读 / 现代重述 / 我的理解）待随学习进度逐卦填入。</p><h2 id="初学时可以先怎么用这页" tabindex="-1">初学时可以先怎么用这页 <a class="header-anchor" href="#初学时可以先怎么用这页" aria-label="Permalink to &quot;初学时可以先怎么用这页&quot;">​</a></h2><ul><li>先把目录看熟，不急着背解释</li><li>每读到一个卦，就回到这里给自己定位</li><li>遇到反复出现的词，再回到 <a href="/Dao/yijing/basics/core-concepts">核心概念</a></li></ul><h2 id="后续建议补法" tabindex="-1">后续建议补法 <a class="header-anchor" href="#后续建议补法" aria-label="Permalink to &quot;后续建议补法&quot;">​</a></h2><ul><li>按卦序或兴趣，每学一卦补入三问解读与个人理解</li><li>关联相关概念（如 <a href="/Dao/yijing/basics/concepts/yin-yang">阴阳</a>、<a href="/Dao/yijing/basics/concepts/wei">位</a>、<a href="/Dao/yijing/basics/concepts/ying">应</a>）</li><li>补入卦与卦之间的往来关系（综卦、错卦）</li></ul>',6))])}const b=l(s,[["render",c]]);export{x as __pageData,b as default};
